import React, { useEffect, useState } from "react";
import axios from "axios";
import "./Internship.css";

export default function Internship() {
  const [internships, setInternships] = useState([]);
  const [filteredInternships, setFilteredInternships] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [editingInternship, setEditingInternship] = useState(null);
  const [form, setForm] = useState({
    title: "",
    company: "",
    location: "",
    type: "",
    description: "",
    stipend: "",
  });

  const user = JSON.parse(localStorage.getItem("user"));
  const role = user?.role || "";

  useEffect(() => {
    fetchInternships();
  }, []);

  useEffect(() => {
    if (searchTerm === "") {
      setFilteredInternships(internships);
    } else {
      const filtered = internships.filter((i) =>
        i.title.toLowerCase().includes(searchTerm.toLowerCase())
      );
      setFilteredInternships(filtered);
    }
  }, [searchTerm, internships]);

  const fetchInternships = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/internships");
      setInternships(res.data);
    } catch (err) {
      console.error("Error fetching internships", err);
    }
  };

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSave = async () => {
    try {
      if (editingInternship) {
        await axios.put(
          `http://localhost:5000/api/internships/${editingInternship._id}`,
          form
        );
      } else {
        await axios.post("http://localhost:5000/api/internships", form);
      }
      fetchInternships();
      setForm({
        title: "",
        company: "",
        location: "",
        type: "",
        description: "",
        stipend: "",
      });
      setEditingInternship(null);
    } catch (err) {
      console.error("Error saving internship", err);
    }
  };

  const handleEdit = (internship) => {
    setForm(internship);
    setEditingInternship(internship);
  };

  const handleDelete = async (id) => {
    try {
      await axios.delete(`http://localhost:5000/api/internships/${id}`);
      fetchInternships();
    } catch (err) {
      console.error("Error deleting internship", err);
    }
  };

  const handleApply = async (internshipId) => {
    try {
      await axios.post(
        `http://localhost:5000/api/applications/apply/${internshipId}`,
        {},
        {
          headers: {
            Authorization: `Bearer ${user.token}`,
          },
        }
      );
      alert("Applied successfully");
    } catch (err) {
      console.error("Error applying", err);
    }
  };

  if (!user) {
    return <p className="message">Please log in to view internships.</p>;
  }

  return (
    <div className="internship-container">
      <h2>Internship Opportunities</h2>

      <input
        type="text"
        placeholder="Search internships..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
        className="search-input"
      />

      {(role === "Admin" || role === "HR") && (
        <div className="form-section">
          <h3>{editingInternship ? "Edit Internship" : "Post Internship"}</h3>
          <input name="title" placeholder="Title" value={form.title} onChange={handleChange} />
          <input name="company" placeholder="Company" value={form.company} onChange={handleChange} />
          <input name="location" placeholder="Location" value={form.location} onChange={handleChange} />
          <input name="type" placeholder="Type (e.g., Remote)" value={form.type} onChange={handleChange} />
          <input name="stipend" placeholder="Stipend" value={form.stipend} onChange={handleChange} />
          <textarea name="description" placeholder="Description" value={form.description} onChange={handleChange} />
          <button onClick={handleSave}>
            {editingInternship ? "Update" : "Post"}
          </button>
        </div>
      )}

      <div className="internship-list">
        {filteredInternships.map((i) => (
          <div className="internship-card" key={i._id}>
            <h4>{i.title}</h4>
            <p><strong>Company:</strong> {i.company}</p>
            <p><strong>Location:</strong> {i.location}</p>
            <p><strong>Type:</strong> {i.type}</p>
            <p><strong>Stipend:</strong> {i.stipend}</p>
            <p><strong>Description:</strong> {i.description}</p>

            {role === "Student" && (
              <button onClick={() => handleApply(i._id)}>Apply</button>
            )}
            {(role === "Admin" || role === "HR") && (
              <div>
                <button onClick={() => handleEdit(i)}>Edit</button>
                <button onClick={() => handleDelete(i._id)}>Delete</button>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
}
